###Resource limit and request assingment 

for n in $(oc get nodes -o name | awk -F/ '{print $2}'); do oc describe node "$n" | awk -v node="$n" ' /Allocated resources:/ {capture=1; next} capture && /^ cpu[[:space:]]/ { # Requests req=$2 gsub("m","",req) cpu_req=req/1000 req_pct=$3 gsub("[()%]","",req_pct) # Limits lim=$4 gsub("m","",lim) cpu_lim=lim/1000 lim_pct=$5 gsub("[()%]","",lim_pct) cpu_req_val=cpu_req cpu_req_pc=req_pct cpu_lim_val=cpu_lim cpu_lim_pc=lim_pct } capture && /^ memory[[:space:]]/ { # Requests req=$2 gsub("Mi","",req) mem_req=req/1024 req_pct=$3 gsub("[()%]","",req_pct) # Limits lim=$4 gsub("Mi","",lim) mem_lim=lim/1024 lim_pct=$5 gsub("[()%]","",lim_pct) printf "%s\t%.2f\t%s\t%.2f\t%s\t%.2f\t%s\t%.2f\t%s\n", node, cpu_req_val, cpu_req_pc, cpu_lim_val, cpu_lim_pc, mem_req, req_pct, mem_lim, lim_pct capture=0 } ' done | column -t -N \ "Node,CPU_Req(Cores),CPU_Req(%),CPU_Lim(Cores),CPU_Lim(%),Mem_Req(GiB),Mem_Req(%),Mem_Lim(GiB),Mem_Lim(%)"
